1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	function calculatePremium(items: any[]): number {
11	  if (items.length === 0) {
12	    return PROCESSING_FEE;
13	  }
14	
15	  const basePremium = BASE_PREMIUMS[items[0].type];
16	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
17	  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
18	}
19	
20	export function processScenario(scenario: any): unknown {
21	  const { items } = scenario.steps[0];
22	  const premium = calculatePremium(items);
23	
24	  return { results: [{ premium }] };
25	}
